export const batch1 = [
  // ========== ERROR SPOTTING (ids 1-80) ==========
  // --- Subject-Verb Agreement (15 Qs) ---
  { id: 1, qtype: 'error-spotting', question: 'Find the error: (A) The team of players (B) are going (C) to the stadium. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"The team" is a collective noun treated as singular. It should be "is going" not "are going".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-1' },
  { id: 2, qtype: 'error-spotting', question: 'Find the error: (A) Each of the boys (B) have completed (C) their assignment on time. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Each" is a singular indefinite pronoun. It should be "has completed" not "have completed".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-2' },
  { id: 3, qtype: 'error-spotting', question: 'Find the error: (A) Neither the teacher (B) nor the students (C) was present in the hall. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'With "neither...nor", the verb agrees with the nearer subject. "Students" is plural, so it should be "were present".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-3' },
  { id: 4, qtype: 'error-spotting', question: 'Find the error: (A) The news (B) are very disturbing (C) for the whole family. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"News" is an uncountable noun and always takes a singular verb. It should be "is very disturbing".', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-4' },
  { id: 5, qtype: 'error-spotting', question: 'Find the error: (A) Bread and butter (B) are served (C) at every breakfast table. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Bread and butter" refers to a single item (a combined concept). It should be "is served".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-5' },
  { id: 6, qtype: 'error-spotting', question: 'Find the error: (A) One of the boys (B) who was standing (C) near the door ran away. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'The relative pronoun "who" refers to "boys" (plural). It should be "who were standing".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-6' },
  { id: 7, qtype: 'error-spotting', question: 'Find the error: (A) The quality of the mangoes (B) were not good (C) this season. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'The subject is "quality" (singular), not "mangoes". It should be "was not good".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-1' },
  { id: 8, qtype: 'error-spotting', question: 'Find the error: (A) Mathematics (B) are a difficult subject (C) for many students. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Mathematics" is treated as a singular noun. It should be "is a difficult subject".', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-4' },
  { id: 9, qtype: 'error-spotting', question: 'Find the error: (A) A large number of students (B) has failed (C) in the examination this year. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"A large number of" takes a plural verb. It should be "have failed".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-7' },
  { id: 10, qtype: 'error-spotting', question: 'Find the error: (A) The committee (B) have taken (C) a unanimous decision. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'When a collective noun acts as a single unit (unanimous decision), use a singular verb: "has taken".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-1' },
  { id: 11, qtype: 'error-spotting', question: 'Find the error: (A) Many a student (B) have failed (C) to understand this concept. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Many a" takes a singular verb. It should be "has failed".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-8' },
  { id: 12, qtype: 'error-spotting', question: 'Find the error: (A) Two-thirds of the city (B) have been destroyed (C) in the earthquake. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'When a fraction refers to a singular noun ("city"), the verb is singular: "has been destroyed".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-9' },
  { id: 13, qtype: 'error-spotting', question: 'Find the error: (A) The furniture in the rooms (B) need to be (C) replaced immediately. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Furniture" is an uncountable noun and takes a singular verb. It should be "needs to be".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-4' },
  { id: 14, qtype: 'error-spotting', question: 'Find the error: (A) Not only the students (B) but also the teacher (C) were punished for the incident. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'With "not only...but also", the verb agrees with the nearer subject "the teacher" (singular): "was punished".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-3' },
  { id: 15, qtype: 'error-spotting', question: 'Find the error: (A) The cattle (B) is grazing (C) in the field near the river. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Cattle" is always plural. It should be "are grazing".', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-10' },

  // --- Tenses (15 Qs) ---
  { id: 16, qtype: 'error-spotting', question: 'Find the error: (A) He told me (B) that he is going (C) to Delhi the next day. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'In reported speech with a past reporting verb, "is going" should change to "was going".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-1' },
  { id: 17, qtype: 'error-spotting', question: 'Find the error: (A) I have visited (B) the Taj Mahal (C) last year during the holidays. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'Present perfect ("have visited") cannot be used with a specific past time ("last year"). It should be "I visited".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-2' },
  { id: 18, qtype: 'error-spotting', question: 'Find the error: (A) When I reached the station, (B) the train already left (C) the platform. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'The train leaving happened before reaching the station. Past perfect is needed: "the train had already left".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-3' },
  { id: 19, qtype: 'error-spotting', question: 'Find the error: (A) If it will rain tomorrow, (B) we shall not go (C) to the picnic. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'In conditional clauses with "if", simple present is used, not future tense. It should be "If it rains tomorrow".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-4' },
  { id: 20, qtype: 'error-spotting', question: 'Find the error: (A) She is working (B) in this company (C) since 2015. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'With "since" indicating a duration from the past to now, present perfect continuous is needed: "She has been working".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-5' },
  { id: 21, qtype: 'error-spotting', question: 'Find the error: (A) I wish (B) I was a bird (C) so that I could fly freely. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'In wishes about unreal present situations, the subjunctive "were" is used: "I wish I were a bird".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Tenses', ruleTag: 'T-6' },
  { id: 22, qtype: 'error-spotting', question: 'Find the error: (A) He said that (B) the earth moved (C) around the sun. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'Universal truths remain in the present tense even in reported speech: "the earth moves around the sun".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-7' },
  { id: 23, qtype: 'error-spotting', question: 'Find the error: (A) By the time you come, (B) I will finish (C) all the work assigned to me. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"By the time" indicates completion before another future event. Future perfect is needed: "I will have finished".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Tenses', ruleTag: 'T-8' },
  { id: 24, qtype: 'error-spotting', question: 'Find the error: (A) Hardly had he reached (B) the station (C) when the train will depart. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: '"Hardly...when" uses past perfect + simple past. It should be "when the train departed".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Tenses', ruleTag: 'T-9' },
  { id: 25, qtype: 'error-spotting', question: 'Find the error: (A) No sooner did the bell ring (B) when all the students (C) rushed out of the classroom. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"No sooner...than" is the correct correlative conjunction, not "no sooner...when". Replace "when" with "than".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-10' },
  { id: 26, qtype: 'error-spotting', question: 'Find the error: (A) He has been (B) reading this novel (C) for the past two hours. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(D)', explanation: 'The sentence is correct. Present perfect continuous with "for" indicates an action that started in the past and continues to the present.', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Tenses', ruleTag: 'T-5' },
  { id: 27, qtype: 'error-spotting', question: 'Find the error: (A) The building (B) is being constructed (C) since last January. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'With "since", present perfect continuous passive is needed: "has been being constructed" or rephrase to "has been under construction".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Tenses', ruleTag: 'T-5' },
  { id: 28, qtype: 'error-spotting', question: 'Find the error: (A) It is time (B) you start (C) preparing for the competitive exams. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"It is time" is followed by past tense to express urgency. It should be "you started".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Tenses', ruleTag: 'T-11' },
  { id: 29, qtype: 'error-spotting', question: 'Find the error: (A) She told me (B) that she will come (C) to the party the next day. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'In reported speech with past reporting verb, "will" changes to "would": "that she would come".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-1' },
  { id: 30, qtype: 'error-spotting', question: 'Find the error: (A) Unless you will work hard, (B) you cannot (C) succeed in life. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Unless" introduces a conditional clause and takes simple present, not future. It should be "Unless you work hard".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-4' },

  // --- Articles (10 Qs) ---
  { id: 31, qtype: 'error-spotting', question: 'Find the error: (A) He is (B) a honest man (C) in the entire village. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Honest" starts with a vowel sound (the "h" is silent). It should be "an honest man".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Articles', ruleTag: 'ART-1' },
  { id: 32, qtype: 'error-spotting', question: 'Find the error: (A) I saw (B) an European tourist (C) at the monument yesterday. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"European" starts with a consonant sound /j/. It should be "a European tourist".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Articles', ruleTag: 'ART-1' },
  { id: 33, qtype: 'error-spotting', question: 'Find the error: (A) The gold (B) is a precious metal (C) found in many countries. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'When speaking of a substance in general, no article is used. It should be "Gold is a precious metal".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Articles', ruleTag: 'ART-2' },
  { id: 34, qtype: 'error-spotting', question: 'Find the error: (A) He was elected (B) the chairman (C) of the managing committee. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'When a person is appointed/elected to a unique position, no article is used before the title: "elected chairman".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Articles', ruleTag: 'ART-3' },
  { id: 35, qtype: 'error-spotting', question: 'Find the error: (A) I play (B) the cricket (C) every Sunday with my friends. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'No article is used before names of games or sports. It should be "play cricket".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Articles', ruleTag: 'ART-4' },
  { id: 36, qtype: 'error-spotting', question: 'Find the error: (A) The Ganges (B) is a longest river (C) in India. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'The superlative "longest" requires the definite article: "is the longest river".', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Articles', ruleTag: 'ART-5' },
  { id: 37, qtype: 'error-spotting', question: 'Find the error: (A) She plays (B) piano (C) very well at the concert hall. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'Musical instruments take "the" before them: "plays the piano".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Articles', ruleTag: 'ART-6' },
  { id: 38, qtype: 'error-spotting', question: 'Find the error: (A) The Mount Everest (B) is the highest peak (C) in the world. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'No article is used before names of mountains or peaks. It should be "Mount Everest".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Articles', ruleTag: 'ART-7' },
  { id: 39, qtype: 'error-spotting', question: 'Find the error: (A) She is (B) an M.A. in English (C) from Delhi University. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(D)', explanation: 'The sentence is correct. "M.A." begins with the vowel sound /em/, so "an" is correct.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Articles', ruleTag: 'ART-1' },
  { id: 40, qtype: 'error-spotting', question: 'Find the error: (A) She went to (B) the hospital (C) to visit a sick friend. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(D)', explanation: 'The sentence is correct. "The hospital" is appropriate when visiting someone, as opposed to going as a patient.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Articles', ruleTag: 'ART-8' },

  // --- Prepositions (10 Qs) ---
  { id: 41, qtype: 'error-spotting', question: 'Find the error: (A) The teacher was angry (B) on the student (C) for not completing the homework. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'The correct preposition with "angry" when directed at a person is "with": "angry with the student".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-1' },
  { id: 42, qtype: 'error-spotting', question: 'Find the error: (A) He has been suffering (B) from fever (C) since three days. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: '"Since" is used with a point in time, "for" is used with a period of time. It should be "for three days".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-2' },
  { id: 43, qtype: 'error-spotting', question: 'Find the error: (A) She is married (B) with a doctor (C) from Chennai. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'The correct preposition with "married" is "to": "married to a doctor".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-3' },
  { id: 44, qtype: 'error-spotting', question: 'Find the error: (A) I congratulated him (B) for his success (C) in the examination. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Congratulate" takes the preposition "on": "congratulated him on his success".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Prepositions', ruleTag: 'PREP-4' },
  { id: 45, qtype: 'error-spotting', question: 'Find the error: (A) She is superior (B) than her colleagues (C) in every respect. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Superior" takes "to" not "than": "superior to her colleagues". Latin comparatives use "to".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-5' },
  { id: 46, qtype: 'error-spotting', question: 'Find the error: (A) He prevented me (B) to go (C) to the market alone. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Prevent" is followed by "from + gerund": "prevented me from going".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Prepositions', ruleTag: 'PREP-6' },
  { id: 47, qtype: 'error-spotting', question: 'Find the error: (A) The train arrived (B) at the station (C) in time. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: '"On time" means punctually (as scheduled). "In time" means before a deadline. For scheduled arrivals, "on time" is correct.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Prepositions', ruleTag: 'PREP-7' },
  { id: 48, qtype: 'error-spotting', question: 'Find the error: (A) We discussed (B) about the matter (C) for over two hours. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Discuss" is a transitive verb and does not take a preposition. It should be "discussed the matter".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-8' },
  { id: 49, qtype: 'error-spotting', question: 'Find the error: (A) He is fond (B) in reading novels (C) during his spare time. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Fond" takes the preposition "of": "fond of reading novels".', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Prepositions', ruleTag: 'PREP-9' },
  { id: 50, qtype: 'error-spotting', question: 'Find the error: (A) The thief entered (B) into the house (C) through the back door. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Enter" is transitive and does not require "into". It should be "entered the house".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-8' },

  // --- Pronouns (8 Qs) ---
  { id: 51, qtype: 'error-spotting', question: 'Find the error: (A) Everyone should do (B) their best (C) to help others in need. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'In formal grammar (as tested in SSC exams), "everyone" is singular and traditionally takes "his" or "his/her": "his best" or "one\'s best".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Pronouns', ruleTag: 'PRO-1' },
  { id: 52, qtype: 'error-spotting', question: 'Find the error: (A) It is me (B) who is responsible (C) for this mistake. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'After "it is", the subjective case is used in formal grammar: "It is I who am responsible".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Pronouns', ruleTag: 'PRO-2' },
  { id: 53, qtype: 'error-spotting', question: 'Find the error: (A) Between you and I, (B) this plan (C) will never succeed. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'After a preposition ("between"), the objective case is used: "Between you and me".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Pronouns', ruleTag: 'PRO-3' },
  { id: 54, qtype: 'error-spotting', question: 'Find the error: (A) One must do (B) his duty (C) towards one\'s country. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'When "one" is used as the subject, the pronoun should consistently be "one\'s": "one must do one\'s duty".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Pronouns', ruleTag: 'PRO-4' },
  { id: 55, qtype: 'error-spotting', question: 'Find the error: (A) He and myself (B) went to the market (C) to buy some vegetables. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Myself" is a reflexive pronoun and cannot be used as a subject. It should be "He and I".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Pronouns', ruleTag: 'PRO-5' },
  { id: 56, qtype: 'error-spotting', question: 'Find the error: (A) Whom do you think (B) is the best candidate (C) for this position? (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'The pronoun is the subject of "is the best candidate". The subjective case "Who" is needed: "Who do you think is the best candidate?"', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Pronouns', ruleTag: 'PRO-6' },
  { id: 57, qtype: 'error-spotting', question: 'Find the error: (A) The boy which (B) was standing near the gate (C) is my brother. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Which" is used for things, not people. It should be "The boy who was standing".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Pronouns', ruleTag: 'PRO-7' },
  { id: 58, qtype: 'error-spotting', question: 'Find the error: (A) Neither of the two boys (B) have done (C) his homework properly. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Neither" is singular and takes a singular verb: "has done".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Pronouns', ruleTag: 'PRO-1' },

  // --- Modifiers (7 Qs) ---
  { id: 59, qtype: 'error-spotting', question: 'Find the error: (A) Walking along the road, (B) a car hit (C) the old man from behind. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'Dangling modifier: "Walking along the road" should modify the old man, not the car. Correct: "a car hit the old man" should be restructured so the man is the subject.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Modifiers', ruleTag: 'MOD-1' },
  { id: 60, qtype: 'error-spotting', question: 'Find the error: (A) Being a rainy day, (B) I decided (C) to stay at home. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'Dangling participle: "Being a rainy day" wrongly modifies "I". Correct: "It being a rainy day" or "As it was a rainy day".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Modifiers', ruleTag: 'MOD-1' },
  { id: 61, qtype: 'error-spotting', question: 'Find the error: (A) I only ate (B) two chapatis (C) for lunch today. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Only" is misplaced. It should modify "two chapatis": "I ate only two chapatis".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Modifiers', ruleTag: 'MOD-2' },
  { id: 62, qtype: 'error-spotting', question: 'Find the error: (A) Opening the door, (B) the room was found (C) in a complete mess. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'Dangling modifier: "Opening the door" needs a human subject. The room cannot open the door. It should name who opened the door.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Modifiers', ruleTag: 'MOD-1' },
  { id: 63, qtype: 'error-spotting', question: 'Find the error: (A) He almost worked (B) the entire day (C) without taking a break. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Almost" is misplaced. It should modify "the entire day": "He worked almost the entire day".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Modifiers', ruleTag: 'MOD-2' },
  { id: 64, qtype: 'error-spotting', question: 'Find the error: (A) Seen from above, (B) the city looked (C) like a beautiful garden. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(D)', explanation: 'The sentence is correct. "Seen from above" correctly modifies "the city" as a reduced passive clause.', level: 'Medium', tier: 'both', examProb: 'Recurring', grammarTopic: 'Modifiers', ruleTag: 'MOD-1' },
  { id: 65, qtype: 'error-spotting', question: 'Find the error: (A) Having not completed (B) the assignment, (C) the teacher scolded him. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: 'The correct form is "Not having completed". The negative "not" comes before the participle.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Modifiers', ruleTag: 'MOD-3' },

  // --- Parallelism (5 Qs) ---
  { id: 66, qtype: 'error-spotting', question: 'Find the error: (A) She likes singing, dancing (B) and to paint (C) in her free time. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'Parallel structure requires consistent forms. "Singing, dancing, and painting" (all gerunds) is correct.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Parallelism', ruleTag: 'PAR-1' },
  { id: 67, qtype: 'error-spotting', question: 'Find the error: (A) The teacher asked the students (B) to read the chapter, answer the questions (C) and that they should write a summary. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'Parallel structure with infinitives: "to read..., answer..., and write a summary" (all infinitives without repeating "to").', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Parallelism', ruleTag: 'PAR-1' },
  { id: 68, qtype: 'error-spotting', question: 'Find the error: (A) He is not only intelligent (B) but also he is (C) hardworking and sincere. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Not only...but also" requires parallel placement. It should be "not only intelligent but also hardworking".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Parallelism', ruleTag: 'PAR-2' },
  { id: 69, qtype: 'error-spotting', question: 'Find the error: (A) The book was interesting, (B) informative, and (C) it had good illustrations. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'The list should maintain parallel adjective form: "interesting, informative, and well-illustrated".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Parallelism', ruleTag: 'PAR-1' },
  { id: 70, qtype: 'error-spotting', question: 'Find the error: (A) Walking in the park, (B) reading books, and (C) to meditate are his hobbies. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'Parallel structure requires all items in the same form: "Walking..., reading..., and meditating" (all gerunds).', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Parallelism', ruleTag: 'PAR-1' },

  // --- Mixed/No Error (10 Qs) ---
  { id: 71, qtype: 'error-spotting', question: 'Find the error: (A) He is one of those men (B) who does not know (C) what integrity is. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Who" refers to "those men" (plural), so the verb should be "do not know".', level: 'Hard', tier: 'tier2', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-6' },
  { id: 72, qtype: 'error-spotting', question: 'Find the error: (A) He asked me (B) that where I was going (C) at that late hour. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: 'In indirect questions, "that" and "where" cannot be used together. Remove "that": "He asked me where I was going".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Reported Speech', ruleTag: 'RS-1' },
  { id: 73, qtype: 'error-spotting', question: 'Find the error: (A) Despite of being rich, (B) he leads (C) a very simple life. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Despite" does not take "of". Use either "Despite being rich" or "In spite of being rich".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Conjunctions', ruleTag: 'CONJ-1' },
  { id: 74, qtype: 'error-spotting', question: 'Find the error: (A) The sceneries of (B) Kashmir are (C) very beautiful and enchanting. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(A)', explanation: '"Scenery" is an uncountable noun and has no plural form. It should be "The scenery of".', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Nouns', ruleTag: 'N-1' },
  { id: 75, qtype: 'error-spotting', question: 'Find the error: (A) The Principal along with (B) the teachers (C) were present at the function. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'With "along with", the verb agrees with the first subject "The Principal" (singular): "was present".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-11' },
  { id: 76, qtype: 'error-spotting', question: 'Find the error: (A) She availed (B) the opportunity (C) to study abroad without hesitation. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Avail" is used reflexively: "availed herself of the opportunity".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Verbs', ruleTag: 'V-1' },
  { id: 77, qtype: 'error-spotting', question: 'Find the error: (A) The reason for (B) his failure is because (C) he did not study properly. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"The reason...is because" is redundant. Use "The reason...is that" or simply "because".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Redundancy', ruleTag: 'RED-1' },
  { id: 78, qtype: 'error-spotting', question: 'Find the error: (A) He gave me (B) many informations (C) about the new project. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(B)', explanation: '"Information" is an uncountable noun. It should be "much information" or "a lot of information".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Nouns', ruleTag: 'N-1' },
  { id: 79, qtype: 'error-spotting', question: 'Find the error: (A) The officer ordered (B) his subordinates (C) to not leave the premises. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(C)', explanation: 'The correct form with infinitive negation is "not to leave", not "to not leave" (split infinitive, marked wrong in SSC).', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Verbs', ruleTag: 'V-2' },
  { id: 80, qtype: 'error-spotting', question: 'Find the error: (A) The Prime Minister, (B) who was elected recently, (C) has announced a new policy. (D) No error', options: ['(A)', '(B)', '(C)', '(D)'], answer: '(D)', explanation: 'The sentence is correct. The relative clause is properly set off by commas, and all grammar is sound.', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Mixed', ruleTag: 'MIX-1' },

  // ========== FILL IN THE BLANKS (ids 81-140) ==========
  { id: 81, qtype: 'fill-blank', question: 'The teacher _____ the students for their excellent performance.', options: ['commended', 'condemned', 'commanded', 'commenced'], answer: 'commended', explanation: '"Commended" means to praise formally. "Condemned" = criticize, "commanded" = ordered, "commenced" = began.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-1' },
  { id: 82, qtype: 'fill-blank', question: 'The government has decided to _____ the old bridge because it is unsafe.', options: ['demolish', 'diminish', 'publish', 'furnish'], answer: 'demolish', explanation: '"Demolish" means to destroy or tear down a structure. "Diminish" = reduce, "publish" = print, "furnish" = supply.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-2' },
  { id: 83, qtype: 'fill-blank', question: 'His speech was so _____ that the audience was moved to tears.', options: ['eloquent', 'elegant', 'elaborate', 'elementary'], answer: 'eloquent', explanation: '"Eloquent" means fluent and persuasive in speech. "Elegant" = graceful, "elaborate" = detailed, "elementary" = basic.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-3' },
  { id: 84, qtype: 'fill-blank', question: 'The company has _____ a new policy to improve employee welfare.', options: ['implemented', 'implicated', 'complicated', 'duplicated'], answer: 'implemented', explanation: '"Implemented" means put into effect. "Implicated" = involved in wrongdoing, "complicated" = made complex, "duplicated" = copied.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-4' },
  { id: 85, qtype: 'fill-blank', question: 'The judge _____ the accused of all charges due to lack of evidence.', options: ['acquitted', 'convicted', 'accused', 'arrested'], answer: 'acquitted', explanation: '"Acquitted" means to declare not guilty. "Convicted" = declared guilty, "accused" = charged, "arrested" = detained.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-5' },
  { id: 86, qtype: 'fill-blank', question: 'The politician made a _____ promise to reduce unemployment within a year.', options: ['bold', 'bald', 'cold', 'fold'], answer: 'bold', explanation: '"Bold" means daring or courageous. "Bald" = hairless, "cold" = chilly, "fold" = bend. "Bold promise" is the correct collocation.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-6' },
  { id: 87, qtype: 'fill-blank', question: 'The new law is expected to _____ corruption in the public sector.', options: ['curb', 'curve', 'cure', 'carve'], answer: 'curb', explanation: '"Curb" means to restrain or control. "Curve" = bend, "cure" = heal, "carve" = cut.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-7' },
  { id: 88, qtype: 'fill-blank', question: 'She _____ her responsibilities with great dedication and commitment.', options: ['discharged', 'discarded', 'discounted', 'discovered'], answer: 'discharged', explanation: '"Discharged" means carried out duties. "Discarded" = threw away, "discounted" = reduced price, "discovered" = found.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-8' },
  { id: 89, qtype: 'fill-blank', question: 'The witness gave a _____ account of the accident to the police.', options: ['vivid', 'valid', 'vapid', 'vacant'], answer: 'vivid', explanation: '"Vivid" means producing powerful mental images. "Valid" = logical, "vapid" = dull, "vacant" = empty.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-9' },
  { id: 90, qtype: 'fill-blank', question: 'The doctor advised the patient to _____ from eating oily food.', options: ['abstain', 'obtain', 'sustain', 'retain'], answer: 'abstain', explanation: '"Abstain from" means to refrain from. "Obtain" = get, "sustain" = maintain, "retain" = keep.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-10' },
  { id: 91, qtype: 'fill-blank', question: 'If I _____ you, I would not accept this offer.', options: ['were', 'was', 'am', 'be'], answer: 'were', explanation: 'In conditional sentences expressing unreal situations, the subjunctive "were" is used regardless of the subject.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Conditionals', ruleTag: 'T-6' },
  { id: 92, qtype: 'fill-blank', question: 'He _____ hard since morning to finish the project on time.', options: ['has been working', 'is working', 'was working', 'had worked'], answer: 'has been working', explanation: '"Since morning" indicates an action starting in the past and continuing to the present, requiring present perfect continuous.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Tenses', ruleTag: 'T-5' },
  { id: 93, qtype: 'fill-blank', question: 'The accused was _____ of the crime and sentenced to prison.', options: ['convicted', 'convinced', 'converted', 'conserved'], answer: 'convicted', explanation: '"Convicted" means found guilty. "Convinced" = persuaded, "converted" = changed, "conserved" = preserved.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-5' },
  { id: 94, qtype: 'fill-blank', question: 'The manager asked the employee to _____ the report before submitting it.', options: ['scrutinize', 'scandalize', 'symbolize', 'synchronize'], answer: 'scrutinize', explanation: '"Scrutinize" means to examine carefully. "Scandalize" = shock, "symbolize" = represent, "synchronize" = coordinate timing.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-11' },
  { id: 95, qtype: 'fill-blank', question: 'The rebels tried to _____ the government through a military coup.', options: ['overthrow', 'overlook', 'overcome', 'overflow'], answer: 'overthrow', explanation: '"Overthrow" means to remove from power. "Overlook" = ignore, "overcome" = defeat difficulties, "overflow" = spill over.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-12' },
  { id: 96, qtype: 'fill-blank', question: 'She could not _____ her tears when she heard the tragic news.', options: ['restrain', 'restrict', 'restore', 'resume'], answer: 'restrain', explanation: '"Restrain" means to hold back. "Restrict" = limit, "restore" = bring back, "resume" = continue.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-13' },
  { id: 97, qtype: 'fill-blank', question: 'The ancient ruins _____ thousands of tourists every year.', options: ['attract', 'attack', 'attach', 'attain'], answer: 'attract', explanation: '"Attract" means to draw interest or visitors. "Attack" = assault, "attach" = connect, "attain" = achieve.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-14' },
  { id: 98, qtype: 'fill-blank', question: 'The speaker _____ the audience with his witty remarks and anecdotes.', options: ['enthralled', 'entitled', 'enrolled', 'endured'], answer: 'enthralled', explanation: '"Enthralled" means captivated or fascinated. "Entitled" = gave a right, "enrolled" = registered, "endured" = suffered.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-15' },
  { id: 99, qtype: 'fill-blank', question: 'The soldiers showed great _____ in the face of danger during the mission.', options: ['valour', 'value', 'volume', 'venture'], answer: 'valour', explanation: '"Valour" means great courage in battle. "Value" = worth, "volume" = quantity, "venture" = risky undertaking.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-16' },
  { id: 100, qtype: 'fill-blank', question: 'The new evidence helped to _____ the innocent man who had been wrongly imprisoned.', options: ['exonerate', 'exaggerate', 'excavate', 'evaporate'], answer: 'exonerate', explanation: '"Exonerate" means to absolve or clear of blame. "Exaggerate" = overstate, "excavate" = dig, "evaporate" = turn to vapor.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-17' },
  { id: 101, qtype: 'fill-blank', question: 'He _____ apologize to the teacher for his rude behaviour.', options: ['ought to', 'ought', 'should to', 'must to'], answer: 'ought to', explanation: '"Ought to" is the correct modal expression meaning should. "Should" does not take "to", and "must" does not take "to".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Modals', ruleTag: 'MOD-4' },
  { id: 102, qtype: 'fill-blank', question: 'The company suffered _____ losses due to the economic recession.', options: ['enormous', 'anonymous', 'erroneous', 'harmonious'], answer: 'enormous', explanation: '"Enormous" means very large. "Anonymous" = unknown name, "erroneous" = incorrect, "harmonious" = peaceful.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-18' },
  { id: 103, qtype: 'fill-blank', question: 'The police _____ the area thoroughly but found no trace of the suspect.', options: ['combed', 'climbed', 'combined', 'combated'], answer: 'combed', explanation: '"Combed" means searched thoroughly and systematically. "Climbed" = ascended, "combined" = merged, "combated" = fought.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-19' },
  { id: 104, qtype: 'fill-blank', question: 'Had I known about the meeting, I _____ attended it without fail.', options: ['would have', 'will have', 'would', 'had'], answer: 'would have', explanation: 'In third conditional (past unreal), "Had I known" requires "would have + past participle" in the result clause.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Conditionals', ruleTag: 'T-12' },
  { id: 105, qtype: 'fill-blank', question: 'The principal _____ the students against using mobile phones in the campus.', options: ['cautioned', 'captured', 'cancelled', 'calculated'], answer: 'cautioned', explanation: '"Cautioned" means warned. "Captured" = seized, "cancelled" = called off, "calculated" = computed.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-20' },
  { id: 106, qtype: 'fill-blank', question: 'His _____ behaviour at the party embarrassed everyone present there.', options: ['obnoxious', 'obvious', 'oblivious', 'observant'], answer: 'obnoxious', explanation: '"Obnoxious" means extremely unpleasant. "Obvious" = clear, "oblivious" = unaware, "observant" = watchful.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-21' },
  { id: 107, qtype: 'fill-blank', question: 'The committee will _____ the proposals and announce the results next week.', options: ['evaluate', 'evacuate', 'evaporate', 'elaborate'], answer: 'evaluate', explanation: '"Evaluate" means to assess or judge. "Evacuate" = empty/vacate, "evaporate" = vaporize, "elaborate" = explain in detail.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-22' },
  { id: 108, qtype: 'fill-blank', question: 'The charity organization works for the _____ of the underprivileged sections of society.', options: ['welfare', 'warfare', 'wardrobe', 'warehouse'], answer: 'welfare', explanation: '"Welfare" means well-being. "Warfare" = fighting, "wardrobe" = clothes/closet, "warehouse" = storage facility.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-23' },
  { id: 109, qtype: 'fill-blank', question: 'The scientist made a _____ discovery that changed the course of medical research.', options: ['groundbreaking', 'heartbreaking', 'backbreaking', 'breathtaking'], answer: 'groundbreaking', explanation: '"Groundbreaking" means innovative or pioneering. "Heartbreaking" = causing grief, "backbreaking" = exhausting, "breathtaking" = stunning.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-24' },
  { id: 110, qtype: 'fill-blank', question: 'The students were asked to _____ the experiment under the guidance of their professor.', options: ['conduct', 'contract', 'construct', 'conflict'], answer: 'conduct', explanation: '"Conduct" means to carry out. "Contract" = shrink/agreement, "construct" = build, "conflict" = clash.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-25' },
  { id: 111, qtype: 'fill-blank', question: 'The leader\'s _____ speech inspired the entire nation to fight for freedom.', options: ['stirring', 'staring', 'steering', 'storing'], answer: 'stirring', explanation: '"Stirring" means arousing strong feelings. "Staring" = gazing, "steering" = guiding, "storing" = keeping.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-26' },
  { id: 112, qtype: 'fill-blank', question: 'No sooner had the chief guest arrived _____ the programme started.', options: ['than', 'when', 'then', 'that'], answer: 'than', explanation: '"No sooner...than" is the correct correlative conjunction pair. "When" goes with "hardly/scarcely".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Conjunctions', ruleTag: 'T-10' },
  { id: 113, qtype: 'fill-blank', question: 'The old man walked _____ he could to reach the hospital before dark.', options: ['as fast as', 'so fast as', 'more fast as', 'too fast as'], answer: 'as fast as', explanation: '"As...as" is used in positive comparisons of equality. "So...as" is used only in negative sentences.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Comparisons', ruleTag: 'COMP-1' },
  { id: 114, qtype: 'fill-blank', question: 'The dictator ruled the country with an iron fist and showed no _____ to his opponents.', options: ['clemency', 'currency', 'fluency', 'frequency'], answer: 'clemency', explanation: '"Clemency" means mercy or leniency. "Currency" = money system, "fluency" = smooth speaking, "frequency" = rate of occurrence.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-27' },
  { id: 115, qtype: 'fill-blank', question: 'She has a _____ for classical music and attends concerts regularly.', options: ['penchant', 'pendant', 'pennant', 'penance'], answer: 'penchant', explanation: '"Penchant" means a strong liking. "Pendant" = necklace piece, "pennant" = flag, "penance" = punishment for sin.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-28' },
  { id: 116, qtype: 'fill-blank', question: 'The child was _____ by the colourful balloons at the fair.', options: ['fascinated', 'frustrated', 'fabricated', 'fluctuated'], answer: 'fascinated', explanation: '"Fascinated" means strongly attracted or charmed. "Frustrated" = annoyed, "fabricated" = invented, "fluctuated" = varied.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-29' },
  { id: 117, qtype: 'fill-blank', question: 'The newspaper published a _____ report on the corruption scandal.', options: ['scathing', 'soothing', 'smoothing', 'seething'], answer: 'scathing', explanation: '"Scathing" means severely critical. "Soothing" = calming, "smoothing" = making smooth, "seething" = intensely angry.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-30' },
  { id: 118, qtype: 'fill-blank', question: 'The teacher asked the students _____ they had completed their assignments.', options: ['whether', 'weather', 'that', 'what'], answer: 'whether', explanation: '"Whether" introduces an indirect yes/no question. "Weather" = climate, "that/what" do not fit yes/no question structure.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Conjunctions', ruleTag: 'CONJ-2' },
  { id: 119, qtype: 'fill-blank', question: 'His _____ attitude towards his colleagues made him unpopular at work.', options: ['condescending', 'commending', 'commanding', 'corresponding'], answer: 'condescending', explanation: '"Condescending" means showing superiority. "Commending" = praising, "commanding" = authoritative, "corresponding" = matching.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-31' },
  { id: 120, qtype: 'fill-blank', question: 'The government has taken _____ measures to control the spread of the disease.', options: ['stringent', 'stagnant', 'strident', 'succulent'], answer: 'stringent', explanation: '"Stringent" means strict or severe. "Stagnant" = not moving, "strident" = loud/harsh, "succulent" = juicy.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-32' },
  { id: 121, qtype: 'fill-blank', question: 'The manager _____ the employee for coming late to office repeatedly.', options: ['reprimanded', 'recommended', 'recompensed', 'recuperated'], answer: 'reprimanded', explanation: '"Reprimanded" means rebuked formally. "Recommended" = suggested, "recompensed" = compensated, "recuperated" = recovered.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-33' },
  { id: 122, qtype: 'fill-blank', question: 'Hardly _____ the station when the train arrived at the platform.', options: ['had I reached', 'I had reached', 'did I reach', 'I reached'], answer: 'had I reached', explanation: 'When "hardly" begins a sentence, the subject-auxiliary inversion occurs: "Hardly had I reached".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Grammar - Inversion', ruleTag: 'T-9' },
  { id: 123, qtype: 'fill-blank', question: 'The summit meeting was _____ due to disagreements between the two nations.', options: ['called off', 'called on', 'called up', 'called for'], answer: 'called off', explanation: '"Called off" means cancelled. "Called on" = visited, "called up" = telephoned, "called for" = demanded.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Phrasal Verbs', ruleTag: 'PV-1' },
  { id: 124, qtype: 'fill-blank', question: 'The politician tried to _____ the public by making false promises before elections.', options: ['deceive', 'receive', 'perceive', 'conceive'], answer: 'deceive', explanation: '"Deceive" means to mislead or trick. "Receive" = get, "perceive" = understand, "conceive" = imagine/become pregnant.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-34' },
  { id: 125, qtype: 'fill-blank', question: 'The investigation brought to light several _____ in the company\'s financial records.', options: ['discrepancies', 'discoveries', 'disciplines', 'discourses'], answer: 'discrepancies', explanation: '"Discrepancies" means inconsistencies or differences. "Discoveries" = findings, "disciplines" = fields/controls, "discourses" = discussions.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-35' },
  { id: 126, qtype: 'fill-blank', question: 'The students were asked to _____ the essay in not more than 200 words.', options: ['condense', 'condemn', 'confine', 'confuse'], answer: 'condense', explanation: '"Condense" means to shorten or summarize. "Condemn" = criticize, "confine" = restrict, "confuse" = bewilder.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-36' },
  { id: 127, qtype: 'fill-blank', question: 'The child showed a _____ talent for painting from a very young age.', options: ['remarkable', 'removable', 'reasonable', 'reachable'], answer: 'remarkable', explanation: '"Remarkable" means worthy of attention, extraordinary. "Removable" = can be removed, "reasonable" = fair, "reachable" = accessible.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-37' },
  { id: 128, qtype: 'fill-blank', question: 'He worked very hard lest he _____ fail in the examination.', options: ['should', 'would', 'could', 'might'], answer: 'should', explanation: '"Lest" is followed by "should" in formal English. It expresses fear that something might happen.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Grammar - Conjunctions', ruleTag: 'CONJ-3' },
  { id: 129, qtype: 'fill-blank', question: 'The _____ of the refugees touched the hearts of people across the globe.', options: ['plight', 'flight', 'blight', 'slight'], answer: 'plight', explanation: '"Plight" means a dangerous or difficult situation. "Flight" = act of flying, "blight" = disease/decay, "slight" = minor.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-38' },
  { id: 130, qtype: 'fill-blank', question: 'The architect designed a _____ building that won several international awards.', options: ['magnificent', 'malignant', 'magnanimous', 'malicious'], answer: 'magnificent', explanation: '"Magnificent" means impressively beautiful. "Malignant" = cancerous, "magnanimous" = generous, "malicious" = spiteful.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-39' },
  { id: 131, qtype: 'fill-blank', question: 'She takes after her mother _____ looks, but her father in temperament.', options: ['in', 'with', 'for', 'by'], answer: 'in', explanation: '"Take after someone in something" is the correct preposition usage meaning to resemble.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Grammar - Prepositions', ruleTag: 'PREP-10' },
  { id: 132, qtype: 'fill-blank', question: 'The athlete\'s _____ performance at the Olympics made the entire nation proud.', options: ['stellar', 'sterile', 'stale', 'stable'], answer: 'stellar', explanation: '"Stellar" means exceptionally good or outstanding. "Sterile" = barren, "stale" = not fresh, "stable" = steady.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-40' },
  { id: 133, qtype: 'fill-blank', question: 'The villagers are wholly _____ on agriculture for their livelihood.', options: ['dependent', 'dependant', 'independent', 'independence'], answer: 'dependent', explanation: '"Dependent" (adjective) means relying on. "Dependant" (noun) is a person who depends on another. "Dependent on" is the correct phrase.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-41' },
  { id: 134, qtype: 'fill-blank', question: 'The minister\'s remarks were taken out of _____ by the opposition party.', options: ['context', 'contact', 'content', 'contract'], answer: 'context', explanation: '"Taken out of context" means words quoted without surrounding information that gives them proper meaning.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-42' },
  { id: 135, qtype: 'fill-blank', question: 'She was _____ to learn that she had won the national-level competition.', options: ['elated', 'elevated', 'elected', 'elaborated'], answer: 'elated', explanation: '"Elated" means extremely happy. "Elevated" = raised, "elected" = chosen by voting, "elaborated" = explained in detail.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-43' },
  { id: 136, qtype: 'fill-blank', question: 'The court _____ the builder to pay compensation to the affected residents.', options: ['directed', 'diverted', 'deserted', 'detected'], answer: 'directed', explanation: '"Directed" means ordered or instructed officially. "Diverted" = redirected, "deserted" = abandoned, "detected" = discovered.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-44' },
  { id: 137, qtype: 'fill-blank', question: 'The child _____ a high fever and had to be rushed to the hospital.', options: ['developed', 'devised', 'devoted', 'devolved'], answer: 'developed', explanation: '"Developed a fever" is the correct collocation meaning to start showing symptoms. "Devised" = invented, "devoted" = dedicated.', level: 'Easy', tier: 'both', examProb: 'Recurring', grammarTopic: 'Vocabulary', ruleTag: 'VOC-45' },
  { id: 138, qtype: 'fill-blank', question: 'The opposition party staged a walkout to _____ against the new legislation.', options: ['protest', 'protect', 'project', 'prospect'], answer: 'protest', explanation: '"Protest" means to express strong objection. "Protect" = safeguard, "project" = estimate/plan, "prospect" = possibility.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Vocabulary', ruleTag: 'VOC-46' },
  { id: 139, qtype: 'fill-blank', question: 'The committee has been _____ to investigate the allegations of fraud.', options: ['constituted', 'constructed', 'constricted', 'constrained'], answer: 'constituted', explanation: '"Constituted" means officially formed or established. "Constructed" = built, "constricted" = tightened, "constrained" = restricted.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Vocabulary', ruleTag: 'VOC-47' },
  { id: 140, qtype: 'fill-blank', question: 'The prime minister _____ upon all citizens to maintain peace and harmony.', options: ['called', 'fell', 'pulled', 'drew'], answer: 'called', explanation: '"Called upon" means urged or appealed to. "Fell upon" = attacked, "pulled upon" is incorrect, "drew upon" = utilized.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Phrasal Verbs', ruleTag: 'PV-2' },

  // ========== SENTENCE IMPROVEMENT (ids 141-200) ==========
  { id: 141, qtype: 'sentence-improvement', question: 'He is more taller than his brother.', options: ['is taller', 'is most taller', 'is the tallest', 'No improvement needed'], answer: 'is taller', explanation: 'Comparative adjectives like "taller" do not need "more". "More" is used with multi-syllable adjectives.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Comparatives', ruleTag: 'COMP-2' },
  { id: 142, qtype: 'sentence-improvement', question: 'She said that she will come tomorrow.', options: ['would come the next day', 'will come the next day', 'shall come tomorrow', 'No improvement needed'], answer: 'would come the next day', explanation: 'In reported speech with past tense, "will" changes to "would" and "tomorrow" changes to "the next day".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Reported Speech', ruleTag: 'T-1' },
  { id: 143, qtype: 'sentence-improvement', question: 'I am living in Delhi since 2010.', options: ['have been living', 'was living', 'had been living', 'No improvement needed'], answer: 'have been living', explanation: 'With "since" indicating a duration from past to present, present perfect continuous is required.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-5' },
  { id: 144, qtype: 'sentence-improvement', question: 'He denied to help me in the project.', options: ['denied helping me', 'denied for helping me', 'denied from helping me', 'No improvement needed'], answer: 'denied helping me', explanation: '"Deny" is followed by a gerund (verb+ing), not an infinitive. "Denied helping" is correct.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Gerund vs Infinitive', ruleTag: 'V-3' },
  { id: 145, qtype: 'sentence-improvement', question: 'The children enjoyed during the picnic yesterday.', options: ['enjoyed themselves during', 'enjoyed at', 'were enjoyed during', 'No improvement needed'], answer: 'enjoyed themselves during', explanation: '"Enjoy" is a reflexive verb and needs a reflexive pronoun or a direct object: "enjoyed themselves".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Verbs', ruleTag: 'V-1' },
  { id: 146, qtype: 'sentence-improvement', question: 'Each boy and each girl were given a prize at the function.', options: ['was given a prize', 'has given a prize', 'are given a prize', 'No improvement needed'], answer: 'was given a prize', explanation: '"Each...and each..." takes a singular verb: "was given".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-2' },
  { id: 147, qtype: 'sentence-improvement', question: 'He asked me where did I live.', options: ['where I lived', 'where do I live', 'where I live', 'No improvement needed'], answer: 'where I lived', explanation: 'In indirect questions, normal word order (not inverted) is used, and tense shifts to past: "where I lived".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Reported Speech', ruleTag: 'RS-1' },
  { id: 148, qtype: 'sentence-improvement', question: 'You need not to worry about the examination results.', options: ['need not worry', 'not need worry', 'need to not worry', 'No improvement needed'], answer: 'need not worry', explanation: 'As a modal verb, "need" is followed directly by the base verb without "to": "need not worry".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Modals', ruleTag: 'MOD-4' },
  { id: 149, qtype: 'sentence-improvement', question: 'The furniture are very expensive in this showroom.', options: ['The furniture is', 'The furnitures are', 'The furnitures is', 'No improvement needed'], answer: 'The furniture is', explanation: '"Furniture" is an uncountable noun and always takes a singular verb.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Nouns', ruleTag: 'N-1' },
  { id: 150, qtype: 'sentence-improvement', question: 'He is the more intelligent of the three brothers.', options: ['the most intelligent', 'more intelligent', 'most intelligent', 'No improvement needed'], answer: 'the most intelligent', explanation: 'When comparing three or more, the superlative "most intelligent" is used, not the comparative "more intelligent".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Comparatives', ruleTag: 'COMP-3' },
  { id: 151, qtype: 'sentence-improvement', question: 'The teacher made the students to complete the assignment.', options: ['made the students complete', 'made the students completing', 'made the students completed', 'No improvement needed'], answer: 'made the students complete', explanation: 'After "make" (causative verb), the bare infinitive is used without "to": "made the students complete".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Verbs', ruleTag: 'V-4' },
  { id: 152, qtype: 'sentence-improvement', question: 'Scarcely had he entered the room than the lights went off.', options: ['when the lights went off', 'before the lights went off', 'then the lights went off', 'No improvement needed'], answer: 'when the lights went off', explanation: '"Scarcely...when" is the correct correlative. "Scarcely...than" is incorrect. "No sooner...than" is a different pair.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Correlatives', ruleTag: 'T-10' },
  { id: 153, qtype: 'sentence-improvement', question: 'One of the student has not submitted the form yet.', options: ['One of the students', 'One of the student\'s', 'One in the student', 'No improvement needed'], answer: 'One of the students', explanation: '"One of" is always followed by a plural noun: "One of the students".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Nouns', ruleTag: 'N-2' },
  { id: 154, qtype: 'sentence-improvement', question: 'He is too intelligent to not solve this simple problem.', options: ['too intelligent not to solve', 'so intelligent to not solve', 'very intelligent to not solve', 'No improvement needed'], answer: 'too intelligent not to solve', explanation: 'The correct structure is "too + adjective + not + to + verb". The negative should come before the infinitive marker.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Sentence Structure', ruleTag: 'SS-1' },
  { id: 155, qtype: 'sentence-improvement', question: 'Despite of working hard, he could not pass the examination.', options: ['Despite working hard', 'Despite he worked hard', 'Despite for working hard', 'No improvement needed'], answer: 'Despite working hard', explanation: '"Despite" is never followed by "of". Use "Despite + noun/gerund" or "In spite of + noun/gerund".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Conjunctions', ruleTag: 'CONJ-1' },
  { id: 156, qtype: 'sentence-improvement', question: 'We reached at the station just in time to catch the train.', options: ['reached the station', 'reached to the station', 'reached in the station', 'No improvement needed'], answer: 'reached the station', explanation: '"Reach" is a transitive verb and does not take a preposition. "Reached the station" is correct.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-8' },
  { id: 157, qtype: 'sentence-improvement', question: 'Unless you do not work hard, you will not succeed in life.', options: ['Unless you work hard', 'Unless you will work hard', 'Unless you did not work hard', 'No improvement needed'], answer: 'Unless you work hard', explanation: '"Unless" already carries a negative meaning. Adding "not" creates a double negative. Remove "not".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Conjunctions', ruleTag: 'CONJ-4' },
  { id: 158, qtype: 'sentence-improvement', question: 'He suggested me to apply for the job immediately.', options: ['suggested that I apply', 'suggested me for applying', 'suggested me applying', 'No improvement needed'], answer: 'suggested that I apply', explanation: '"Suggest" takes a that-clause with subjunctive, not an infinitive: "suggested that I apply".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Verbs', ruleTag: 'V-5' },
  { id: 159, qtype: 'sentence-improvement', question: 'I prefer tea than coffee in the morning.', options: ['tea to coffee', 'tea over coffee', 'tea from coffee', 'No improvement needed'], answer: 'tea to coffee', explanation: '"Prefer" takes "to" not "than": "prefer tea to coffee".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-5' },
  { id: 160, qtype: 'sentence-improvement', question: 'The train had left before I reached at the station.', options: ['reached the station', 'reached to the station', 'reached in the station', 'No improvement needed'], answer: 'reached the station', explanation: '"Reach" is transitive and does not require a preposition before its object.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-8' },
  { id: 161, qtype: 'sentence-improvement', question: 'Would you mind to close the window please?', options: ['mind closing', 'mind close', 'mind to closing', 'No improvement needed'], answer: 'mind closing', explanation: '"Mind" is followed by a gerund: "Would you mind closing the window?"', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Gerund vs Infinitive', ruleTag: 'V-3' },
  { id: 162, qtype: 'sentence-improvement', question: 'He is one of the best player in the team this season.', options: ['best players', 'better player', 'good player', 'No improvement needed'], answer: 'best players', explanation: '"One of the" is always followed by a plural noun: "one of the best players".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Nouns', ruleTag: 'N-2' },
  { id: 163, qtype: 'sentence-improvement', question: 'She was so tired that she could not hardly walk to the bus stop.', options: ['could hardly walk', 'could not walk hardly', 'cannot hardly walk', 'No improvement needed'], answer: 'could hardly walk', explanation: '"Hardly" is a negative word. Using "not" with "hardly" creates a double negative. Remove "not".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Double Negatives', ruleTag: 'DN-1' },
  { id: 164, qtype: 'sentence-improvement', question: 'No less than fifty students attended the seminar yesterday.', options: ['No fewer than fifty', 'Not less than fifty', 'No lesser than fifty', 'No improvement needed'], answer: 'No fewer than fifty', explanation: '"Fewer" is used for countable nouns (students), while "less" is for uncountable nouns.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Adjectives', ruleTag: 'ADJ-1' },
  { id: 165, qtype: 'sentence-improvement', question: 'The data shows that the economy is recovering from the recession.', options: ['The data show', 'The datas show', 'The data have shown', 'No improvement needed'], answer: 'The data show', explanation: '"Data" is the plural of "datum". Formally, it takes a plural verb: "The data show".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Nouns', ruleTag: 'N-3' },
  { id: 166, qtype: 'sentence-improvement', question: 'He insisted on me to go with him to the market.', options: ['insisted on my going', 'insisted that I go', 'insisted me to go', 'No improvement needed'], answer: 'insisted on my going', explanation: '"Insist on" takes a possessive + gerund: "insisted on my going". Alternatively, "insisted that I go" works too.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Gerund vs Infinitive', ruleTag: 'V-3' },
  { id: 167, qtype: 'sentence-improvement', question: 'If I was you, I would take this opportunity without hesitation.', options: ['If I were you', 'If I am you', 'If I had been you', 'No improvement needed'], answer: 'If I were you', explanation: 'In unreal conditional sentences, the subjunctive "were" is used: "If I were you".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Conditionals', ruleTag: 'T-6' },
  { id: 168, qtype: 'sentence-improvement', question: 'He is working here since the last five years.', options: ['has been working here for', 'was working here since', 'had been working here for', 'No improvement needed'], answer: 'has been working here for', explanation: 'Present perfect continuous is needed with duration. "For" is used with a period of time, and "the last" is dropped.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-5' },
  { id: 169, qtype: 'sentence-improvement', question: 'The minister was too glad to meet the delegates from abroad.', options: ['was very glad', 'was so glad', 'was glad enough', 'No improvement needed'], answer: 'was very glad', explanation: '"Too" implies excess leading to a negative result. Being glad is positive, so "very glad" is appropriate.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Adverbs', ruleTag: 'ADV-1' },
  { id: 170, qtype: 'sentence-improvement', question: 'He availed of the opportunity to go abroad for higher studies.', options: ['availed himself of', 'availed the', 'availed for', 'No improvement needed'], answer: 'availed himself of', explanation: '"Avail" is used reflexively: "availed himself of the opportunity".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Verbs', ruleTag: 'V-1' },
  { id: 171, qtype: 'sentence-improvement', question: 'The reason for his absence is because he was feeling unwell.', options: ['is that he', 'is since he', 'is due to he', 'No improvement needed'], answer: 'is that he', explanation: '"The reason is because" is redundant. Use "The reason is that" to avoid redundancy.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Redundancy', ruleTag: 'RED-1' },
  { id: 172, qtype: 'sentence-improvement', question: 'She is knowing the answer to this difficult question.', options: ['knows the answer', 'has known the answer', 'was knowing the answer', 'No improvement needed'], answer: 'knows the answer', explanation: '"Know" is a stative verb and is not used in continuous tenses. Simple present "knows" is correct.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Tenses', ruleTag: 'T-13' },
  { id: 173, qtype: 'sentence-improvement', question: 'The government have announced a new policy for farmers.', options: ['The government has announced', 'The government are announcing', 'The government were announced', 'No improvement needed'], answer: 'The government has announced', explanation: 'In Indian English SSC usage, "government" as an institution takes a singular verb: "has announced".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-1' },
  { id: 174, qtype: 'sentence-improvement', question: 'She told to me that she was feeling much better now.', options: ['She told me', 'She said to me', 'She was telling me', 'No improvement needed'], answer: 'She told me', explanation: '"Tell" is followed directly by the indirect object without "to": "told me". "Said to me" is also correct but with "said".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Reported Speech', ruleTag: 'RS-2' },
  { id: 175, qtype: 'sentence-improvement', question: 'He ran so fastly that nobody could catch him during the race.', options: ['so fast that', 'so faster that', 'very fastly that', 'No improvement needed'], answer: 'so fast that', explanation: '"Fast" is both an adjective and an adverb. "Fastly" is not a word. The correct form is "so fast that".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Adverbs', ruleTag: 'ADV-2' },
  { id: 176, qtype: 'sentence-improvement', question: 'The officer ordered the clerk to dispose the old files immediately.', options: ['dispose of the old files', 'dispose off the old files', 'disposing the old files', 'No improvement needed'], answer: 'dispose of the old files', explanation: '"Dispose of" (with "of") means to get rid of. "Dispose" alone does not carry this meaning.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-11' },
  { id: 177, qtype: 'sentence-improvement', question: 'The criminal was hung by the neck until he was dead.', options: ['was hanged', 'has been hung', 'had hung', 'No improvement needed'], answer: 'was hanged', explanation: '"Hanged" is the correct past tense when referring to execution. "Hung" is used for objects.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Verbs', ruleTag: 'V-6' },
  { id: 178, qtype: 'sentence-improvement', question: 'I look forward to hear from you regarding the application.', options: ['to hearing from you', 'to have heard from you', 'for hearing from you', 'No improvement needed'], answer: 'to hearing from you', explanation: 'In "look forward to", the "to" is a preposition followed by a gerund: "to hearing".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Gerund vs Infinitive', ruleTag: 'V-3' },
  { id: 179, qtype: 'sentence-improvement', question: 'He is elder than me by three years.', options: ['older than me', 'elder to me', 'more elder than me', 'No improvement needed'], answer: 'elder to me', explanation: '"Elder" is used for family relationships and takes "to", not "than": "elder to me". Alternatively, "older than me" is correct for general comparison.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Comparatives', ruleTag: 'COMP-4' },
  { id: 180, qtype: 'sentence-improvement', question: 'I could not help but to laugh at his funny jokes.', options: ['help but laugh', 'help to laugh', 'help laughing', 'No improvement needed'], answer: 'help but laugh', explanation: '"Cannot help but" is followed by the bare infinitive without "to": "could not help but laugh".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Verbs', ruleTag: 'V-7' },
  { id: 181, qtype: 'sentence-improvement', question: 'Neither he came nor he wrote a letter to inform us.', options: ['Neither did he come nor did he write', 'Neither he comes nor he writes', 'Neither he had come nor written', 'No improvement needed'], answer: 'Neither did he come nor did he write', explanation: 'After "neither" at the start of a clause, subject-auxiliary inversion is required.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Correlatives', ruleTag: 'PAR-2' },
  { id: 182, qtype: 'sentence-improvement', question: 'He speaks English like he was born in England.', options: ['as if he were', 'as he was', 'like he were', 'No improvement needed'], answer: 'as if he were', explanation: '"As if/as though" is used for unreal comparisons (not "like"), and the subjunctive "were" is needed.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Conditionals', ruleTag: 'T-6' },
  { id: 183, qtype: 'sentence-improvement', question: 'Being a holiday, the school remained closed for the entire day.', options: ['It being a holiday', 'Being it a holiday', 'Having been a holiday', 'No improvement needed'], answer: 'It being a holiday', explanation: 'The participial phrase needs a proper subject. "It being a holiday" provides the correct logical subject.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Modifiers', ruleTag: 'MOD-1' },
  { id: 184, qtype: 'sentence-improvement', question: 'The two first chapters of the book are quite interesting.', options: ['The first two chapters', 'The two chapters first', 'The both first chapters', 'No improvement needed'], answer: 'The first two chapters', explanation: 'Ordinal adjectives ("first") precede cardinal numbers ("two"): "the first two chapters".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Adjectives', ruleTag: 'ADJ-2' },
  { id: 185, qtype: 'sentence-improvement', question: 'He is too honest a person to accept any bribe from anyone.', options: ['No improvement needed', 'very honest a person', 'so honest person', 'such honest person'], answer: 'No improvement needed', explanation: 'The sentence is correct. "Too + adjective + a/an + noun" is the correct structure for emphasis.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Sentence Structure', ruleTag: 'SS-1' },
  { id: 186, qtype: 'sentence-improvement', question: 'She requested him that he should help her with the luggage.', options: ['requested him to help', 'requested for him to help', 'requested that he help', 'No improvement needed'], answer: 'requested him to help', explanation: '"Request" can be followed by "object + to infinitive": "requested him to help".', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Verbs', ruleTag: 'V-5' },
  { id: 187, qtype: 'sentence-improvement', question: 'Inspite of he worked hard, he did not pass the examination.', options: ['In spite of working hard', 'In spite of he working hard', 'In spite that he worked hard', 'No improvement needed'], answer: 'In spite of working hard', explanation: '"In spite of" is followed by a noun or gerund, not a clause: "In spite of working hard".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Conjunctions', ruleTag: 'CONJ-1' },
  { id: 188, qtype: 'sentence-improvement', question: 'He asked me that why I was absent from the class yesterday.', options: ['asked me why I', 'asked me that why was I', 'asked to me why I', 'No improvement needed'], answer: 'asked me why I', explanation: 'In indirect questions, "that" is not used with wh-words: "asked me why I was absent".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Reported Speech', ruleTag: 'RS-1' },
  { id: 189, qtype: 'sentence-improvement', question: 'The more you will read, the more you will understand the subject.', options: ['The more you read', 'The more you are reading', 'The much you read', 'No improvement needed'], answer: 'The more you read', explanation: 'In "the more...the more" comparative structure, simple present is used, not future tense.', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Comparatives', ruleTag: 'COMP-5' },
  { id: 190, qtype: 'sentence-improvement', question: 'These all information are very useful for the project.', options: ['All this information is', 'All these informations are', 'These all informations is', 'No improvement needed'], answer: 'All this information is', explanation: '"Information" is uncountable (no plural). "All" precedes the determiner: "All this information is".', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Nouns', ruleTag: 'N-1' },
  { id: 191, qtype: 'sentence-improvement', question: 'She said she prefers reading more than writing essays.', options: ['prefers reading to writing', 'prefers to read more than write', 'prefers reading rather than writing', 'No improvement needed'], answer: 'prefers reading to writing', explanation: '"Prefer" takes "to" not "more than" when comparing two gerunds: "prefers reading to writing".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-5' },
  { id: 192, qtype: 'sentence-improvement', question: 'The meeting has been postponed to Monday next week.', options: ['postponed till Monday', 'postponed until Monday', 'postponed for Monday', 'No improvement needed'], answer: 'No improvement needed', explanation: '"Postponed to" is correct and means rescheduled to a later date. The sentence needs no improvement.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Prepositions', ruleTag: 'PREP-12' },
  { id: 193, qtype: 'sentence-improvement', question: 'When I went there, I found the door was widely open.', options: ['wide open', 'opened widely', 'broadly open', 'No improvement needed'], answer: 'wide open', explanation: '"Wide open" is the correct expression. "Widely" is used for figurative meaning. "Wide" is the correct flat adverb here.', level: 'Medium', tier: 'both', examProb: 'High', grammarTopic: 'Adverbs', ruleTag: 'ADV-3' },
  { id: 194, qtype: 'sentence-improvement', question: 'She has been absent from school since four days.', options: ['for four days', 'from four days', 'before four days', 'No improvement needed'], answer: 'for four days', explanation: '"For" is used with periods of time (four days). "Since" is used with specific points in time (Monday, 2020).', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Prepositions', ruleTag: 'PREP-2' },
  { id: 195, qtype: 'sentence-improvement', question: 'She did nothing but cried the whole afternoon after hearing the news.', options: ['but cry', 'but crying', 'but to crying', 'No improvement needed'], answer: 'but cry', explanation: 'After "did nothing but", the bare infinitive is used: "did nothing but cry".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Verbs', ruleTag: 'V-7' },
  { id: 196, qtype: 'sentence-improvement', question: 'He could not cope up with the pressure of the new job.', options: ['cope with', 'cope for', 'cope on', 'No improvement needed'], answer: 'cope with', explanation: '"Cope with" is correct. "Cope up with" is incorrect in standard English.', level: 'Easy', tier: 'both', examProb: 'Hot', grammarTopic: 'Phrasal Verbs', ruleTag: 'PV-3' },
  { id: 197, qtype: 'sentence-improvement', question: 'The teacher as well as the students were present at the ceremony.', options: ['was present', 'is present', 'are present', 'No improvement needed'], answer: 'was present', explanation: 'With "as well as", the verb agrees with the first subject ("The teacher" - singular): "was present".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Subject-Verb Agreement', ruleTag: 'SVA-11' },
  { id: 198, qtype: 'sentence-improvement', question: 'Supposing if it rains, what shall we do for the outdoor event?', options: ['Supposing it rains', 'If supposing it rains', 'Suppose if it rains', 'No improvement needed'], answer: 'Supposing it rains', explanation: '"Supposing" already implies a condition. Adding "if" is redundant. "Supposing it rains" is correct.', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Redundancy', ruleTag: 'RED-2' },
  { id: 199, qtype: 'sentence-improvement', question: 'He behaved cowardly during the crisis and abandoned his team.', options: ['in a cowardly manner', 'like a coward', 'cowardlike', 'No improvement needed'], answer: 'in a cowardly manner', explanation: '"Cowardly" is an adjective, not an adverb. To modify the verb "behaved", use "in a cowardly manner" or "like a coward".', level: 'Hard', tier: 'tier2', examProb: 'High', grammarTopic: 'Adverbs', ruleTag: 'ADV-4' },
  { id: 200, qtype: 'sentence-improvement', question: 'The scenery of Kashmir is more beautiful than Shimla.', options: ['than that of Shimla', 'than Shimla\'s scenery', 'compared to Shimla', 'No improvement needed'], answer: 'than that of Shimla', explanation: 'You must compare like with like. "Scenery of Kashmir" should be compared with "scenery of Shimla": use "than that of Shimla".', level: 'Medium', tier: 'both', examProb: 'Hot', grammarTopic: 'Comparatives', ruleTag: 'COMP-6' },
]
